  function ensureNav(){var nav=document.getElementById('oasis-work-nav');if(!nav){nav=document.createElement('nav');nav.id='oasis-work-nav';nav.className='oasis-work-nav';nav.innerHTML='<button data-view="playlist" class="is-active">Lista</button><button data-view="preview">Vivo</button><button data-view="editor">Editor</button><button data-action="close">Cerrar</button>';nav.addEventListener('click',function(e){var b=e.target.closest('button');if(!b)return;if(b.dataset.action==='close'){document.body.classList.remove('oasis-editor-open');return;}nav.querySelectorAll('button[data-view]').forEach(function(x){x.classList.toggle('is-active',x===b);});if(b.dataset.view==='editor'){document.body.classList.add('oasis-editor-open');var real=Array.from(document.querySelectorAll('button')).find(function(x){return /Editor/i.test(x.textContent||'')&&x!==b;});if(real)real.click();}else{document.body.classList.remove('oasis-editor-open');var rx=new RegExp(b.dataset.view==='preview'?'Vivo':'Lista','i');var real2=Array.from(document.querySelectorAll('button')).find(function(x){return rx.test(x.textContent||'')&&x!==b;});if(real2)real2.click();}});document.body.appendChild(nav);}}
